export interface PolicyInput {
  readonly userId: string;
  readonly tier: "free" | "pro";
}

export function chooseRoute(input: PolicyInput): string {
  if (input.tier === "pro") return `priority:${input.userId}`;
  return `standard:${input.userId}`;
}

import { expect, it } from "vitest";
import { chooseRoute } from "./policy.js";

it("routes pro users to priority", () => {
  expect(chooseRoute({ userId: "u1", tier: "pro" })).toBe("priority:u1");
});

import { chooseRoute, type PolicyInput } from "@fixture/domain";

export function handleRequest(input: PolicyInput): { readonly route: string; readonly accepted: boolean } {
  const route = chooseRoute(input);
  return { route, accepted: route.length > 0 };
}

import { expect, it } from "vitest";
import { handleRequest } from "./server.js";

it("accepts routed requests", () => {
  expect(handleRequest({ userId: "u2", tier: "free" })).toEqual({ route: "standard:u2", accepted: true });
});
